require('dotenv').config();
const express = require('express');
const app = express();
const bodyParser = require('body-parser');
const path = require('path');
const axios = require('axios');
const mercadopago = require('mercadopago');
const { Sequelize, DataTypes } = require('sequelize');

const sequelize = new Sequelize({
  dialect: 'sqlite',
  storage: './database.sqlite'
});

const Product = sequelize.define('Product', {
  name: DataTypes.STRING,
  price: DataTypes.FLOAT,
  description: DataTypes.STRING
});

mercadopago.configure({
  access_token: process.env.MP_ACCESS_TOKEN
});

app.set('view engine', 'ejs');
app.set('views', path.join(__dirname, 'views'));
app.use(express.static(path.join(__dirname, 'public')));
app.use(bodyParser.urlencoded({ extended: true }));
app.use(bodyParser.json());

// Rotas
app.get('/', (req, res) => res.render('index'));

app.get('/produtos', async (req, res) => {
  const produtos = await Product.findAll();
  res.render('produtos', { produtos });
});

app.get('/contato', (req, res) => res.render('contato'));

app.post('/create_preference', async (req, res) => {
  try {
    const { items } = req.body;

    const preference = {
      items: items.map(i => ({
        title: i.name,
        quantity: i.quantity,
        unit_price: parseFloat(i.price)
      })),
      back_urls: {
        success: 'https://bizerra-shop-production-url/success',
        failure: 'https://bizerra-shop-production-url/failure',
        pending: 'https://bizerra-shop-production-url/pending'
      },
      auto_return: 'approved'
    };

    const response = await axios.post(
      'https://api.mercadopago.com/checkout/preferences',
      preference,
      {
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${process.env.MP_ACCESS_TOKEN}`
        }
      }
    );

    res.json({ init_point: response.data.init_point });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Erro ao criar preferência de pagamento' });
  }
});

sequelize.sync().then(() => {
  const port = process.env.PORT || 3000;
  app.listen(port, () => console.log(`🚀 Bizerra Shop rodando na porta ${port}`));
});
